((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 75 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kemudian mani itu menjadi segumpal darah, lalu Allah menciptakannya, dan menyempurnakannya,', NOW(), NOW()),
