((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Bukankah telah datang atas manusia satu waktu dari masa, sedang dia ketika itu belum merupakan sesuatu yang dapat disebut?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami telah menciptakan manusia dari setetes mani yang bercampur yang Kami hendak mengujinya (dengan perintah dan larangan), karena itu Kami jadikan dia mendengar dan melihat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami telah menunjukinya jalan yang lurus; ada yang bersyukur dan ada pula yang kafir.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami menyediakan bagi orang-orang kafir rantai, belenggu dan neraka yang menyala-nyala.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya orang-orang yang berbuat kebajikan minum dari gelas (berisi minuman) yang campurannya adalah air kafur,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) mata air (dalam surga) yang daripadanya hamba-hamba Allah minum, yang mereka dapat mengalirkannya dengan sebaik-baiknya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka menunaikan nazar dan takut akan suatu hari yang azabnya merata di mana-mana.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka memberikan makanan yang disukainya kepada orang miskin, anak yatim dan orang yang ditawan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya kami memberi makanan kepadamu hanyalah untuk mengharapkan keridhaan Allah, kami tidak menghendaki balasan dari kamu dan tidak pula (ucapan) terima kasih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya kami takut akan (azab) Tuhan kami pada suatu hari yang (di hari itu) orang-orang bermuka masam penuh kesulitan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka Tuhan memelihara mereka dari kesusahan hari itu, dan memberikan kepada mereka kejernihan (wajah) dan kegembiraan hati.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan Dia memberi balasan kepada mereka karena kesabaran mereka (dengan) surga dan (pakaian) sutera,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'di dalamnya mereka duduk bertelakan di atas dipan, mereka tidak merasakan di dalamnya (teriknya) matahari dan tidak pula dingin yang bersangatan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan naungan (pohon-pohon surga itu) dekat di atas mereka dan buahnya dimudahkan memetiknya semudah-mudahnya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan diedarkan kepada mereka bejana-bejana dari perak dan piala-piala yang bening laksana kaca,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(yaitu) kaca-kaca (yang terbuat) dari perak yang telah diukur mereka dengan sebaik-baiknya.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Di dalam surga itu mereka diberi minum segelas (minuman) yang campurannya adalah jahe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', '(Yang didatangkan dari) sebuah mata air surga yang dinamakan salsabil.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan mereka dikelilingi oleh pelayan-pelayan muda yang tetap muda. Apabila kamu melihat mereka, kamu akan mengira mereka, mutiara yang bertaburan.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan apabila kamu melihat di sana (surga), niscaya kamu akan melihat berbagai macam kenikmatan dan kerajaan yang besar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka memakai pakaian sutera halus yang hijau dan sutera tebal dan dipakaikan kepada mereka gelang terbuat dari perak, dan Tuhan memberikan kepada mereka minuman yang bersih.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya ini adalah balasan untukmu, dan usahamu adalah disyukuri (diberi balasan).', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya Kami telah menurunkan Al Quran kepadamu (hai Muhammad) dengan berangsur-angsur.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka bersabarlah kamu untuk (melaksanakan) ketetapan Tuhanmu, dan janganlah kamu ikuti orang yang berdosa dan orang yang kafir di antar mereka.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 76 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan sebutlah nama Tuhanmu pada (waktu) pagi dan petang.', NOW(), NOW()),
