((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 77 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Demi malaikat-malaikat yang diutus untuk membawa kebaikan,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 77 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan (malaikat-malaikat) yang terbang dengan kencangnya,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 77 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan (malaikat-malaikat) yang menyebarkan (rahmat Tuhannya) dengan seluas-luasnya,', NOW(), NOW()),
